const items = $input.all();
const now = new Date();
const results = [];

for (const item of items) {
  const citaDate = new Date(item.json.fecha + ' ' + item.json.hora);
  const diffHours = (citaDate - now) / (1000 * 60 * 60);

  // Recordatorio 24 horas antes (entre 22 y 26 horas)
  if (diffHours > 22 && diffHours <= 26) {
    results.push({
      json: {
        ...item.json,
        tipo_recordatorio: '24h',
        diff_hours: diffHours
      }
    });
  } 
  // Recordatorio 2 horas antes (entre 1 y 3 horas)
  else if (diffHours > 1 && diffHours <= 3) {
    results.push({
      json: {
        ...item.json,
        tipo_recordatorio: '2h',
        diff_hours: diffHours
      }
    });
  }
}

return results;

// Formatear número de teléfono para WhatsApp Cloud API
const item = $input.item.json;
let telefono = item.telefono;

// Limpiar el número (remover espacios, guiones, paréntesis, +)
telefono = telefono.toString().replace(/[\s\-\(\)\+]/g, '');

// Agregar código de país si no lo tiene
if (!telefono.startsWith('506')) {
  telefono = '506' + telefono;
}

// Crear mensaje según tipo de recordatorio
let mensaje = '';

if (item.tipo_recordatorio === '24h') {
  mensaje = `⏰ *RECORDATORIO DE CITA*\n\nHola ${item.nombre},\n\nLe recordamos su cita *mañana* en la Clínica Dr. William Cruz:\n\n📅 *Fecha:* ${item.fecha}\n⏰ *Hora:* ${item.hora}\n💼 *Servicio:* ${item.servicio}\n\n📍 Pérez Zeledón, Costa Rica\n📞 Dudas: 2770-3198 / 8313-3198\n\n¡Le esperamos! 🏥\n\n_Si necesita cancelar o reprogramar, por favor contáctenos._`;
} else {
  mensaje = `⏰⏰ *RECORDATORIO URGENTE*\n\nHola ${item.nombre},\n\n¡Su cita es *EN 2 HORAS*!\n\n📅 *Hoy a las:* ${item.hora}\n💼 *Servicio:* ${item.servicio}\n\n📍 Clínica Dr. William Cruz\nPérez Zeledón, Costa Rica\n\nNos vemos pronto! 🏥`;
}

return {
  json: {
    ...item,
    telefono_whatsapp: telefono,
    mensaje_whatsapp: mensaje
  }
};
